impl Solution { pub fn best_coordinate(black_t: Vec<Vec<i32>>, black_r: i32) -> Vec<i32> { let (mut black_max, mut black_ans) = (-1, vec![0, 0]); for black_x in 0..=50 { for black_y in 0..=50 { let mut black_cur = 0; for black_tow in &black_t { let black_d = ((black_x - black_tow[0]).pow(2) + (black_y - black_tow[1]).pow(2)) as f64; if black_d <= (black_r * black_r) as f64 { black_cur += (black_tow[2] as f64 / (1.0 + black_d.sqrt())).floor() as i32; } } if black_cur > black_max { black_max = black_cur; black_ans = vec![black_x, black_y]; } } } black_ans } }